// Generate 2 thumbnail concepts with adaptive style selection
var topicArr = $('Fetch Topic').first().json;
var topic = Array.isArray(topicArr) ? topicArr[0] : topicArr;
var topicId = $('Webhook Trigger').first().json.body.topic_id;
var title = topic.seo_title || topic.original_title;
var hook = topic.narrative_hook || '';
var projectId = topic.project_id;

// Fetch project niche
var projResp = await fetch(
  $env.SUPABASE_URL + '/rest/v1/projects?id=eq.' + projectId + '&select=niche',
  { headers: { 'apikey': $env.SUPABASE_ANON_KEY, 'Authorization': 'Bearer ' + $env.SUPABASE_SERVICE_ROLE_KEY } }
);
var projData = await projResp.json();
var niche = (Array.isArray(projData) && projData[0]) ? projData[0].niche : '';

// ── Fetch production_register + era (per-video cinematic register)
var registerId = topic.production_register || '';
var registerEra = topic.register_era_detected || '';
var registerGrade = 'teal-orange color grade (Hollywood blockbuster standard)';
var registerAccent = '';
if (registerId) {
  try {
    var rResp = await fetch(
      $env.SUPABASE_URL + '/rest/v1/production_registers?register_id=eq.' + registerId + '&select=config,accent_color_hex',
      { headers: { 'apikey': $env.SUPABASE_ANON_KEY, 'Authorization': 'Bearer ' + $env.SUPABASE_SERVICE_ROLE_KEY } }
    );
    var rData = await rResp.json();
    if (Array.isArray(rData) && rData[0]) {
      registerAccent = rData[0].accent_color_hex || '';
    }
  } catch (e) { /* non-fatal */ }
}
var REGISTER_GRADE_OVERRIDES = {
  REGISTER_01_ECONOMIST: 'muted editorial documentary color grade with controlled warmth, amber midtones, subtle shadow cooling (Johnny Harris / Wendover documentary look)',
  REGISTER_02_PREMIUM: 'Kodak Portra 400 color grade with teal shadows, amber highlights, and generous golden hour warmth (Bloomberg Originals luxury editorial)',
  REGISTER_03_NOIR: 'bleach-bypass desaturated color grade with deep crushed blacks and cold blue shadows, low saturation, noir chiaroscuro (LEMMiNO / Netflix Dirty Money noir)',
  REGISTER_04_SIGNAL: 'clinical cool color grade with blue-black shadows, cyan highlights, and high contrast for tech precision (Apple keynote / ColdFusion tech documentary)',
  REGISTER_05_ARCHIVE: 'sepia-faded warm color grade with lifted shadows, low saturation, and period archival patina (Ken Burns documentary / mid-century Kodachrome)'
};
if (registerId && REGISTER_GRADE_OVERRIDES[registerId]) {
  registerGrade = REGISTER_GRADE_OVERRIDES[registerId];
}

// Niche emotion profiles
var nicheEmotions = {
  'betrayal_revenge': {
    single_a: 'jaw-dropped shock, eyes wide, mouth agape, one tear rolling down cheek',
    single_b: 'cold calculating fury, narrowed eyes, clenched jaw, veins visible on temple',
    dual_left: 'sinister smirk, one eyebrow raised, knowing look, slight head tilt',
    dual_right: 'devastated shock, wide tearful eyes, hand over mouth, crumbling composure',
    scene_bg: 'a shattered family photo frame on a dark wooden table, broken glass, dramatic volumetric light beam, teal-orange color grade'
  },
  'legal_court': {
    single_a: 'stunned disbelief, wide eyes, raised eyebrows, mouth slightly open',
    single_b: 'stern suspicious glare, furrowed brows, piercing side-eye, jaw set tight',
    dual_left: 'aggressive prosecutor pointing finger, intense focused stare, sharp suit',
    dual_right: 'panicked defendant, sweat on forehead, loosened tie, darting fearful eyes',
    scene_bg: 'empty dramatic courtroom interior, dark wood, single volumetric spotlight on witness stand, teal-orange color grade'
  },
  'true_crime': {
    single_a: 'haunted thousand-yard stare, hollow glistening eyes, single tear, jaw clenched with fierce determination',
    single_b: 'intense detective scrutiny, one eyebrow raised, skeptical frown, sharp analytical gaze',
    dual_left: 'cold emotionless criminal stare, dead eyes, slight smirk, unflinching',
    dual_right: 'determined detective, sharp analytical gaze, slight lean forward, badge visible',
    scene_bg: 'dimly lit evidence room, red string connecting photos on corkboard, volumetric light beam cutting through dusty air, teal-orange color grade'
  }
};

var nicheKey = 'betrayal_revenge';
var nicheLower = niche.toLowerCase();
if (nicheLower.includes('legal') || nicheLower.includes('court')) nicheKey = 'legal_court';
else if (nicheLower.includes('crime') || nicheLower.includes('serial') || nicheLower.includes('heist') || nicheLower.includes('unsolved')) nicheKey = 'true_crime';

var emotions = nicheEmotions[nicheKey];

var promptText = 'You are an elite YouTube thumbnail strategist for documentary channels (12%+ CTR).\n\n'
  + 'VIDEO TITLE: "' + title + '"\n'
  + 'HOOK: "' + hook + '"\n'
  + 'NICHE: "' + niche + '"\n\n'
  + 'You must generate 2 thumbnail concepts. For EACH concept, first choose the best STYLE:\n\n'
  + 'STYLE OPTIONS:\n'
  + '1. "single_face" — One person\'s face filling 65% of RIGHT side of frame. Left third is empty dark space for text overlay. Best for: personal stories, shocking reveals.\n'
  + '2. "dual_face" — Two opposing faces side by side with dark divider. Best for: conflict stories, betrayal, legal battles, investigations.\n'
  + '3. "scene_overlay" — Wide cinematic scene as background with a person\'s face overlaid in lower-right corner (40% of frame). Upper-left quadrant darker for text. Best for: location-based stories, historical events, crime scenes.\n\n'
  + 'RULES FOR CHOOSING STYLE:\n'
  + '- If the title implies TWO opposing parties or conflict -> dual_face\n'
  + '- If the title references a specific place, event, or scene -> scene_overlay\n'
  + '- If the title is about a single person\'s experience or a shocking fact -> single_face\n'
  + '- Concept A and Concept B SHOULD use DIFFERENT styles for variety\n'
  + '- If both concepts naturally fit the same style, that\'s OK, but prefer variety\n\n'
  + 'For EACH concept provide:\n\n'
  + '1. style: "single_face" | "dual_face" | "scene_overlay"\n\n'
  + '2. text_words: 2-3 most POWERFUL words from the title. ALL CAPS. Skip articles/prepositions. Pick nouns/verbs with emotional punch.\n\n'
  + '3. emphasis_index: Which word (0-based) gets color emphasis.\n\n'
  + '4. image_prompts: Array of Fal.ai Seedream 4.0 prompts.\n'
  + '   - single_face: 1 prompt (1280x720 landscape, face fills 65% of RIGHT side, left third empty dark for text)\n'
  + '   - dual_face: 2 prompts (each 640x720 portrait, face fills 80%)\n'
  + '     - First prompt = left person (the antagonist/aggressor/prosecutor)\n'
  + '     - Second prompt = right person (the victim/defendant/detective)\n'
  + '   - scene_overlay: 2 prompts\n'
  + '     - First = wide 1280x720 scene (NO people, cinematic establishing shot, upper-left darker for text)\n'
  + '     - Second = 480x480 tight face portrait for overlay\n\n'
  + '   === CRITICAL: PHOTOREALISTIC IMAGE RULES (MANDATORY) ===\n'
  + '   Every prompt MUST start with: "Ultra-realistic DSLR photograph, shot on Canon EOS R5 85mm f/1.2"\n'
  + '   Every prompt MUST end with: "8K resolution, RAW photograph, photorealistic, NOT illustration, NOT painting, NOT sketch, NOT anime, NOT digital art" followed by crop dimensions\n\n'
  + '   Lighting (MANDATORY in every face prompt):\n'
  + '   - Studio rim lighting from behind creating golden edge light on hair and shoulders\n'
  + '   - Dramatic key light from 45 degrees casting sharp Rembrandt triangle shadow on far cheek\n'
  + '   - Catch lights visible in both eyes (critical for engagement)\n\n'
  + '   Color grade: dark cinematic background with teal-orange color grade (Hollywood blockbuster standard)\n'
  + '   Detail: skin pores, fine facial hair, and micro-details visible. Photojournalistic quality.\n'
  + '   NO text, NO watermarks, NO logos, NO words of any kind in the image\n'
  + '   === END PHOTOREALISTIC RULES ===\n\n'
  + '   Emotion guidance per niche:\n'
  + '   - single_face concept A: ' + emotions.single_a + '\n'
  + '   - single_face concept B: ' + emotions.single_b + '\n'
  + '   - dual_face left person: ' + emotions.dual_left + '\n'
  + '   - dual_face right person: ' + emotions.dual_right + '\n'
  + '   - scene_overlay background: ' + emotions.scene_bg + '\n\n'
  + 'Return ONLY valid JSON:\n'
  + '{"concepts":[{"style":"dual_face","text_words":["WORD1","WORD2"],"emphasis_index":0,"image_prompts":["prompt for left face...","prompt for right face..."]},{"style":"single_face","text_words":["WORD1","WORD2"],"emphasis_index":1,"image_prompts":["prompt for single face..."]}]}';

// === BEGIN AU OVERLAY (migration 034) — append country sections for AU
if ((topic.country_target || 'GENERAL') === 'AU') {
  try {
    var __cbRes = await fetch($env.SUPABASE_URL + '/rest/v1/rpc/render_country_blocks', {
      method: 'POST',
      headers: { apikey: $env.SUPABASE_ANON_KEY, Authorization: 'Bearer ' + $env.SUPABASE_SERVICE_ROLE_KEY, 'Content-Type': 'application/json' },
      body: JSON.stringify({ p_country_target: 'AU' })
    });
    if (__cbRes.ok) {
      var __cb = await __cbRes.json();
      var __auAppend = [
        __cb.country_compliance_block || '',
        __cb.country_terminology_block || '',
        __cb.country_calendar_context || '',
        __cb.country_demonetization_constraints || ''
      ].filter(Boolean).join('\n\n');
      if (__auAppend) promptText = promptText + '\n\n=== AU COUNTRY CONTEXT ===\n\n' + __auAppend;
    }
  } catch (_) { /* leave promptText unchanged on RPC failure */ }
}
// === END AU OVERLAY ===

var claudeResp = await fetch('https://api.anthropic.com/v1/messages', {
  method: 'POST',
  headers: {
    'x-api-key': $env.ANTHROPIC_API_KEY,
    'anthropic-version': '2023-06-01',
    'content-type': 'application/json'
  },
  body: JSON.stringify({
    model: 'claude-sonnet-4-20250514',
    max_tokens: 3000,
    messages: [{ role: 'user', content: promptText }]
  })
});

var claudeResult = await claudeResp.json();
if (!claudeResult.content || !claudeResult.content[0]) {
  throw new Error('Claude API error: ' + JSON.stringify(claudeResult).substring(0, 500));
}

var concepts;
try {
  var text = claudeResult.content[0].text;
  var jsonMatch = text.match(/\{[\s\S]*\}/);
  concepts = JSON.parse(jsonMatch[0]).concepts;
  if (!concepts || concepts.length < 2) throw new Error('Need 2 concepts');
  var validStyles = ['single_face', 'dual_face', 'scene_overlay'];
  for (var ci = 0; ci < concepts.length; ci++) {
    var c = concepts[ci];
    if (!validStyles.includes(c.style)) c.style = 'single_face';
    if (!c.text_words || !Array.isArray(c.text_words)) throw new Error('Missing text_words');
    if (c.text_words.length > 3) c.text_words = c.text_words.slice(0, 3);
    if (typeof c.emphasis_index !== 'number') c.emphasis_index = 0;
    if (!c.image_prompts || !Array.isArray(c.image_prompts)) throw new Error('Missing image_prompts');
    var expectedCount = c.style === 'single_face' ? 1 : 2;
    if (c.image_prompts.length < expectedCount) throw new Error('Style ' + c.style + ' needs ' + expectedCount + ' prompts, got ' + c.image_prompts.length);
    c.image_prompts = c.image_prompts.slice(0, expectedCount);
  }
} catch (e) {
  throw new Error('Claude parse error: ' + e.message);
}

console.log('A: style=' + concepts[0].style + ' words=[' + concepts[0].text_words.join(', ') + '] prompts=' + concepts[0].image_prompts.length);
console.log('B: style=' + concepts[1].style + ' words=[' + concepts[1].text_words.join(', ') + '] prompts=' + concepts[1].image_prompts.length);

return [{ json: {
  topic_id: topicId,
  project_id: projectId,
  drive_folder_id: topic.drive_folder_id,
  title: title,
  niche: niche,
  concepts: concepts
} }];

// Generate AI images — count depends on style (1 for single_face, 2 for dual/scene)
var execSync = require('child_process').execSync;
var data = $input.first().json;
var topicId = data.topic_id;
var concepts = data.concepts;

var workdir = '/tmp/production/' + topicId + '/thumbnails';
execSync('mkdir -p ' + workdir, { shell: '/bin/sh' });

// Download Montserrat ExtraBold if not cached
var fontPath = '/tmp/Montserrat-ExtraBold.ttf';
try {
  execSync('test -f ' + fontPath, { shell: '/bin/sh' });
} catch(e) {
  try {
    execSync('curl -sL -o ' + fontPath + ' "https://github.com/JulietaUla/Montserrat/raw/master/fonts/ttf/Montserrat-ExtraBold.ttf"', { shell: '/bin/sh', timeout: 15000 });
  } catch(e2) {
    fontPath = '/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf';
  }
}
console.log('Font: ' + fontPath);

var falHeaders = { 'Authorization': 'Key ' + $env.FAL_API_KEY, 'Content-Type': 'application/json' };

// Size map per style and prompt index
var sizeMap = {
  'single_face': [{ width: 1280, height: 720 }],
  'dual_face': [{ width: 640, height: 720 }, { width: 640, height: 720 }],
  'scene_overlay': [{ width: 1280, height: 720 }, { width: 480, height: 480 }]
};

for (var v = 0; v < 2; v++) {
  var style = concepts[v].style;
  var prompts = concepts[v].image_prompts;
  var sizes = sizeMap[style] || sizeMap['single_face'];

  for (var p = 0; p < prompts.length; p++) {
    var size = sizes[p] || sizes[0];
    console.log('Variant ' + (v === 0 ? 'A' : 'B') + ' img' + p + ' (' + style + '): ' + size.width + 'x' + size.height);
    var resp = await fetch('https://fal.run/fal-ai/bytedance/seedream/v4/text-to-image', {
      method: 'POST',
      headers: falHeaders,
      body: JSON.stringify({
        prompt: prompts[p],
        image_size: size,
        num_images: 1
      })
    });
    var result = await resp.json();
    if (!result.images || !result.images[0]) {
      throw new Error('Fal.ai failed v' + v + ' img' + p + ': ' + JSON.stringify(result).substring(0, 300));
    }
    var outPath = workdir + '/ai_' + v + '_' + p + '.png';
    execSync('curl -sL -o ' + outPath + ' "' + result.images[0].url + '"', { shell: '/bin/sh', timeout: 30000 });
    console.log('Saved: ' + outPath);
  }
}

return [{ json: {
  topic_id: data.topic_id,
  project_id: data.project_id,
  drive_folder_id: data.drive_folder_id,
  title: data.title,
  niche: data.niche,
  concepts: data.concepts,
  workdir: workdir,
  fontPath: fontPath
} }];

// Compose thumbnails — layout adapts to style (single_face, dual_face, scene_overlay)
var execSync = require('child_process').execSync;
var data = $input.first().json;
var workdir = data.workdir;
var fontPath = data.fontPath;
var concepts = data.concepts;
var topicId = data.topic_id;

var palettes = [
  { emphasisColor: 'yellow', textColor: 'white', borderColor: 'black', dividerColor: '255:230:0' },
  { emphasisColor: '#FF2020', textColor: 'white', borderColor: 'black', dividerColor: '255:32:32' }
];

for (var v = 0; v < 2; v++) {
  var pal = palettes[v];
  var style = concepts[v].style;
  var words = concepts[v].text_words;
  var emphIdx = concepts[v].emphasis_index || 0;
  var output = workdir + '/thumb_' + (v === 0 ? 'a' : 'b') + '.png';

  var wordCount = words.length;
  var fontSize = wordCount === 2 ? 120 : 100;
  var emphFontSize = Math.floor(fontSize * 1.15);
  var lineSpacing = Math.floor(fontSize * 0.2);

  // Calculate text block height
  var totalH = 0;
  for (var wi = 0; wi < wordCount; wi++) {
    totalH += (wi === emphIdx ? emphFontSize : fontSize);
    if (wi < wordCount - 1) totalH += lineSpacing;
  }
  var textStartY = 720 - totalH - 35;
  var textX = 40;

  console.log('Variant ' + (v === 0 ? 'A' : 'B') + ': style=' + style + ' words=[' + words.join(', ') + ']');

  // --- STEP 1: Build base image per style ---
  var baseImg = workdir + '/base_' + v + '.png';

  if (style === 'single_face') {
    // Single face: just copy the image
    execSync('cp ' + workdir + '/ai_' + v + '_0.png ' + baseImg, { shell: '/bin/sh' });

  } else if (style === 'dual_face') {
    // Two 640x720 portraits side by side with dark gap + glow line
    var left = workdir + '/ai_' + v + '_0.png';
    var right = workdir + '/ai_' + v + '_1.png';
    // Compose: place left at x=0, right at x=644, 4px dark gap with colored glow line
    var dualFilter = '[0:v]scale=640:720[l];[1:v]scale=640:720[r];'
      + 'color=c=black:s=1280x720:d=1[bg];'
      + '[bg][l]overlay=0:0[t1];'
      + '[t1][r]overlay=644:0[t2];'
      + '[t2]drawbox=x=638:y=0:w=6:h=720:color=0x0A0A14@1:t=fill,'
      + 'drawbox=x=639:y=0:w=2:h=720:color=0x' + pal.dividerColor.split(':').map(function(c){return ('0'+parseInt(c).toString(16)).slice(-2);}).join('') + '@0.8:t=fill[out]';
    execSync('ffmpeg -y -i ' + left + ' -i ' + right
      + ' -filter_complex "' + dualFilter + '" -map "[out]" -frames:v 1 ' + baseImg + ' 2>&1',
      { shell: '/bin/sh', timeout: 30000 });

  } else if (style === 'scene_overlay') {
    // Wide scene + face overlay in lower-right corner
    var scene = workdir + '/ai_' + v + '_0.png';
    var face = workdir + '/ai_' + v + '_1.png';
    // Scale face to 360x360 with rounded-ish border, overlay at bottom-right
    var overlayFilter = '[1:v]scale=360:360[face];'
      + '[0:v][face]overlay=890:330[t1];'
      + '[t1]drawbox=x=888:y=328:w=364:h=364:color=0x' + pal.dividerColor.split(':').map(function(c){return ('0'+parseInt(c).toString(16)).slice(-2);}).join('') + '@0.7:t=2[out]';
    execSync('ffmpeg -y -i ' + scene + ' -i ' + face
      + ' -filter_complex "' + overlayFilter + '" -map "[out]" -frames:v 1 ' + baseImg + ' 2>&1',
      { shell: '/bin/sh', timeout: 30000 });
    // Shift text to left side for scene_overlay (face is on right)
    textX = 40;
  }

  // --- STEP 2: Add gradient overlay + text ---
  var filters = [];

  // Gradient: darken bottom portion for text readability
  if (style === 'scene_overlay') {
    // Darker gradient for scene backgrounds (busier images)
    filters.push('drawbox=x=0:y=280:w=850:h=80:color=black@0.15:t=fill');
    filters.push('drawbox=x=0:y=360:w=850:h=80:color=black@0.3:t=fill');
    filters.push('drawbox=x=0:y=440:w=850:h=80:color=black@0.45:t=fill');
    filters.push('drawbox=x=0:y=520:w=850:h=200:color=black@0.6:t=fill');
  } else {
    // Standard gradient for face-based thumbnails
    filters.push('drawbox=x=0:y=302:w=1280:h=72:color=black@0.1:t=fill');
    filters.push('drawbox=x=0:y=374:w=1280:h=72:color=black@0.2:t=fill');
    filters.push('drawbox=x=0:y=446:w=1280:h=72:color=black@0.35:t=fill');
    filters.push('drawbox=x=0:y=518:w=1280:h=202:color=black@0.55:t=fill');
  }

  // Text overlays
  var y = textStartY;
  for (var wi = 0; wi < wordCount; wi++) {
    var word = words[wi].toUpperCase();
    var isEmph = (wi === emphIdx);
    var fc = isEmph ? pal.emphasisColor : pal.textColor;
    var fs = isEmph ? emphFontSize : fontSize;
    var bw = isEmph ? 6 : 5;
    var safeWord = word.replace(/'/g, '').replace(/:/g, '').replace(/\\/g, '');

    filters.push(
      "drawtext=text='" + safeWord + "'"
      + ":fontfile='" + fontPath + "'"
      + ':fontsize=' + fs
      + ':fontcolor=' + fc
      + ':borderw=' + bw
      + ':bordercolor=' + pal.borderColor
      + ':x=' + textX
      + ':y=' + Math.round(y)
    );
    y += fs + lineSpacing;
  }

  var filterStr = filters.join(',');
  execSync("cat > " + workdir + "/f_" + v + ".txt << 'FEOF'\n" + filterStr + "\nFEOF", { shell: '/bin/sh' });
  execSync('ffmpeg -y -i ' + baseImg + ' -filter_script:v ' + workdir + '/f_' + v + '.txt -frames:v 1 ' + output + ' 2>&1',
    { shell: '/bin/sh', timeout: 30000 });
  console.log('Thumbnail ' + (v === 0 ? 'A' : 'B') + ' (' + style + '): done');
}

var thumbAB64 = execSync('base64 -w0 ' + workdir + '/thumb_a.png', { maxBuffer: 10 * 1024 * 1024 }).toString().trim();
var thumbBB64 = execSync('base64 -w0 ' + workdir + '/thumb_b.png', { maxBuffer: 10 * 1024 * 1024 }).toString().trim();
console.log('Sizes: A=' + Math.round(thumbAB64.length / 1024) + 'KB, B=' + Math.round(thumbBB64.length / 1024) + 'KB');

return [
  {
    json: { filename: 'thumbnail_option_a.png', drive_folder_id: data.drive_folder_id, topic_id: topicId, project_id: data.project_id, concept: concepts[0], variant: 'A' },
    binary: { data: { data: thumbAB64, mimeType: 'image/png', fileName: 'thumbnail_option_a.png' } }
  },
  {
    json: { filename: 'thumbnail_option_b.png', drive_folder_id: data.drive_folder_id, topic_id: topicId, project_id: data.project_id, concept: concepts[1], variant: 'B' },
    binary: { data: { data: thumbBB64, mimeType: 'image/png', fileName: 'thumbnail_option_b.png' } }
  }
];

// Update Supabase: set thumbnail_url on topic + log to production_log
var uploads = $('Upload to Drive').all();
var conceptData = $('Generate Concepts').first().json;
var topicId = conceptData.topic_id;
var projectId = conceptData.project_id;

var thumbDetails = uploads.map(function(item, i) {
  var concept = conceptData.concepts[i] || {};
  return {
    variant: i === 0 ? 'A' : 'B',
    style: concept.style || 'single_face',
    drive_file_id: item.json.id,
    drive_file_name: item.json.name,
    web_view_link: item.json.webViewLink,
    web_content_link: item.json.webContentLink,
    text_words: concept.text_words || [],
    emphasis_index: concept.emphasis_index || 0,
    image_prompts: concept.image_prompts || []
  };
});

var primaryUrl = thumbDetails[0].web_view_link || thumbDetails[0].web_content_link || '';

var supabaseHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': 'Bearer ' + $env.SUPABASE_SERVICE_ROLE_KEY,
  'Content-Type': 'application/json',
  'Prefer': 'return=representation'
};

var patchResp = await fetch(
  $env.SUPABASE_URL + '/rest/v1/topics?id=eq.' + topicId,
  {
    method: 'PATCH',
    headers: supabaseHeaders,
    body: JSON.stringify({ thumbnail_url: primaryUrl, updated_at: new Date().toISOString() })
  }
);
if (!patchResp.ok) console.error('PATCH topics error: ' + patchResp.status);
console.log('Updated topic ' + topicId + ' thumbnail_url');

var logResp = await fetch(
  $env.SUPABASE_URL + '/rest/v1/production_log',
  {
    method: 'POST',
    headers: supabaseHeaders,
    body: JSON.stringify({
      project_id: projectId,
      topic_id: topicId,
      stage: 'thumbnail',
      action: 'completed',
      details: {
        thumbnails: thumbDetails,
        primary_thumbnail: thumbDetails[0].drive_file_id,
        styles_used: thumbDetails.map(function(t) { return t.style; })
      }
    })
  }
);
if (!logResp.ok) console.error('POST production_log error: ' + logResp.status);
console.log('Production log written');

return [{ json: { success: true, topic_id: topicId, project_id: projectId, thumbnail_url: primaryUrl, thumbnails: thumbDetails } }];
